#nullable enable // autogenerated

using PVZEngine;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2Logic.Entities
{
    [PropertyRegistryRegion(PropertyRegions.entity)]
    public static class LogicBossProps
    {
        private static PropertyMeta<T> Get<T>(string name, T? defaultValue = default, params string[] obsoleteNames)
        {
            return new PropertyMeta<T>(name, defaultValue, obsoleteNames);
        }

        #region 无害
        public static readonly PropertyMeta<bool> DONT_COUNT_BOSS_HP = Get<bool>("dont_count_boss_hp");
        public static bool DontCountBossHP(this Entity enemy)
        {
            return enemy.GetProperty<bool>(DONT_COUNT_BOSS_HP);
        }
        #endregion
    }
}